import heapq

class Solution(object):
    def minTimeToReach(self, moveTime):
        n, m = len(moveTime), len(moveTime[0])
        # State: (time, r, c, parity) where parity=0 means next move costs 1, parity=1 means costs 2
        dist = [[[float('inf')] * 2 for _ in range(m)] for _ in range(n)]
        dist[0][0][0] = 0
        heap = [(0, 0, 0, 0)]  # (time, r, c, parity)
        while heap:
            t, r, c, p = heapq.heappop(heap)
            if t > dist[r][c][p]:
                continue
            cost = 1 if p == 0 else 2
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < n and 0 <= nc < m:
                    nt = max(t, moveTime[nr][nc]) + cost
                    np = 1 - p
                    if nt < dist[nr][nc][np]:
                        dist[nr][nc][np] = nt
                        heapq.heappush(heap, (nt, nr, nc, np))
        return min(dist[n-1][m-1])
